# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    // Player Health
    public static int playerHealth = 100;

    // Currency
    public static int playerCurrency = 0;

    // Shop Prices
    public static Dictionary<string, int> shopPrices = new Dictionary<string, int>()
    {
        {"Sword", 10},
        {"Shield", 20},
        {"Potion", 5}
    };

    // Damage Calculation
    public static int CalculateDamage(int damageValue)
    {
        return (int)(damageValue * 1.2f);
    }

    // Shop Purchase
    public void BuyItem(string item, int amount)
    {
        if (playerCurrency >= shopPrices[item] * amount)
        {
            playerCurrency -= shopPrices[item] * amount;
            if (item == "Sword")
            {
                // Add sword to inventory or upgrade existing one
                Debug.Log("You bought a sword!");
            }
            else if (item == "Shield")
            {
                // Add shield to inventory or upgrade existing one
                Debug.Log("You bought a shield!");
            }
            else if (item == "Potion")
            {
                // Drink potion and heal player health
                playerHealth += 20;
                Debug.Log("You drank a potion! Your health is now: " + playerHealth);
            }
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }

    // Update Currency
    public void UpdateCurrency(int amount)
    {
        playerCurrency += amount;
    }

    // Update Health
    public void UpdateHealth(int damage)
    {
        playerHealth -= CalculateDamage(damage);
        if (playerHealth <= 0)
        {
            // Game Over logic here
            Debug.Log("Game over!");
            Application.Quit();
        }
    }
}

public class PlayerController : MonoBehaviour
{
    public Button swordButton;
    public Button shieldButton;
    public Button potionButton;

    private void Start()
    {
        // Initialize shop buttons
        swordButton.onClick.AddListener(() => BuyItem("Sword", 1));
        shieldButton.onClick.AddListener(() => BuyItem("Shield", 1));
        potionButton.onClick.AddListener(() => BuyItem("Potion", 1));

        // Update currency and health display
        PlayerStats.playerCurrencyDisplay.text = "Currency: " + PlayerStats.playerCurrency;
        PlayerStats.playerHealthDisplay.text = "Health: " + PlayerStats.playerHealth;
    }
}

public class EnemyController : MonoBehaviour
{
    public Button attackButton;

    private void Start()
    {
        // Initialize attack button
        attackButton.onClick.AddListener(() => AttackPlayer());
    }

    private void AttackPlayer()
    {
        // Calculate and apply damage to player health
        PlayerStats.UpdateHealth(20);
    }
}